# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local function check_permissions()
    local uri = ngx.var.uri
    local token = ngx.var.http_authorization
    
    -- Skip permission checks for admin and api endpoints
    if string.find(uri, "/admin") or string.find(uri, "/api") then
        return true
    end
    
    -- Validate token
    if not token or string.sub(token, 1, 7) ~= "Bearer " then
        ngx.status = 401
        ngx.say('Unauthorized')
        ngx.exit(401)
        return false
    end
    
    local user_role = validate_token(string.sub(token, 8))
    if not user_role then
        ngx.status = 401
        ngx.say('Unauthorized')
        ngx.exit(401)
        return false
    end
    
    -- Check role permissions
    if user_role == "admin" then
        return true
    elseif user_role == "user" then
        -- Allow access to specific endpoints for users
        if string.find(uri, "/public") or string.find(uri, "/profile") then
            return true
        else
            ngx.status = 403
            ngx.say('Forbidden')
            ngx.exit(403)
            return false
        end
    else
        ngx.status = 403
        ngx.say('Forbidden')
        ngx.exit(403)
        return false
    end
end

local function validate_token(token)
    -- Simple token validation - in production, use proper JWT validation
    if token == "valid_admin_token" then
        return "admin"
    elseif token == "valid_user_token" then
        return "user"
    else
        return nil
    end
end

check_permissions()